type Test struct {
	Type string
	And  *TestAnd
	Or   *TestOr
}

func (t *Test) GetType() string {
	if t == nil {
		return ""
	}
	return t.Type
}

func (t *Test) GetAnd() *TestAnd {
	if t == nil {
		return nil
	}
	return t.And
}

func (t *Test) GetOr() *TestOr {
	if t == nil {
		return nil
	}
	return t.Or
}

func (t *Test) UnmarshalJSON(data []byte) error {
	var unmarshaler struct {
		Type string `json:"type"`
	}
	if err := json.Unmarshal(data, &unmarshaler); err != nil {
		return err
	}
	t.Type = unmarshaler.Type
	if unmarshaler.Type == "" {
		return fmt.Errorf("%T did not include discriminant type", t)
	}
	switch unmarshaler.Type {
	case "and":
		value := new(TestAnd)
		if err := json.Unmarshal(data, &value); err != nil {
			return err
		}
		t.And = value
	case "or":
		value := new(TestOr)
		if err := json.Unmarshal(data, &value); err != nil {
			return err
		}
		t.Or = value
	}
	return nil
}

func (t Test) MarshalJSON() ([]byte, error) {
	if err := t.validate(); err != nil {
		return nil, err
	}
	if t.And != nil {
		return internal.MarshalJSONWithExtraProperty(t.And, "type", "and")
	}
	if t.Or != nil {
		return internal.MarshalJSONWithExtraProperty(t.Or, "type", "or")
	}
	return nil, fmt.Errorf("type %T does not define a non-empty union type", t)
}

type TestVisitor interface {
	VisitAnd(*TestAnd) error
	VisitOr(*TestOr) error
}

func (t *Test) Accept(visitor TestVisitor) error {
	if t.And != nil {
		return visitor.VisitAnd(t.And)
	}
	if t.Or != nil {
		return visitor.VisitOr(t.Or)
	}
	return fmt.Errorf("type %T does not define a non-empty union type", t)
}

func (t *Test) validate() error {
	if t == nil {
		return fmt.Errorf("type %T is nil", t)
	}
	var fields []string
	if t.And != nil {
		fields = append(fields, "and")
	}
	if t.Or != nil {
		fields = append(fields, "or")
	}
	if len(fields) == 0 {
		if t.Type != "" {
			return fmt.Errorf("type %T defines a discriminant set to %q but the field is not set", t, t.Type)
		}
		return fmt.Errorf("type %T is empty", t)
	}
	if len(fields) > 1 {
		return fmt.Errorf("type %T defines values for %s, but only one value is allowed", t, fields)
	}
	if t.Type != "" {
		field := fields[0]
		if t.Type != field {
			return fmt.Errorf(
				"type %T defines a discriminant set to %q, but it does not match the %T field; either remove or update the discriminant to match",
				t,
				t.Type,
				t,
			)
		}
	}
	return nil
}

